mapper.select:
SELECT ITEM.ITEM_NO AS itemNo , ITEM.ITEM_NAME AS itemName , MIN(ITOP.PRICE) AS price , ITEM.ITEM_STATUS AS itemStatus , IMG.IMG_URL AS imgUrl , CASE WHEN ITEM.CREATED_DT >= DATE_FORMAT(DATE_SUB(NOW(), INTERVAL 15 DAY), '%Y%m%d') THEN TRUE ELSE FALSE END AS isNew , COUNT(DISTINCT ORD.ORDER_NO) AS orderCount , COUNT(DISTINCT ITRV.REVIEW_NO) AS reviewCount FROM ITEM ITEM LEFT JOIN ITEM_OPTION_GROUP ITOG ON ITOG.ITEM_NO = ITEM.ITEM_NO LEFT JOIN ITEM_OPTION ITOP ON ITOP.GROUP_NO = ITOG.GROUP_NO LEFT JOIN ITEM_IMAGES IMG ON IMG.ITEM_NO = ITEM.ITEM_NO AND IMG.PRIMARY_YN = 'Y' LEFT JOIN ORDER_DETAIL ORDE ON ORDE.ITEM_NO = ITEM.ITEM_NO LEFT JOIN `ORDER` ORD ON ORD.ORDER_NO = ORDE.ORDER_NO AND ORD.ORDER_STATUS = 'PAID' LEFT JOIN ITEM_CATEGORY_MAPPING ITCP ON ITCP.ITEM_NO = ITEM.ITEM_NO LEFT JOIN ITEM_REVIEW ITRV ON ITRV.ITEM_NO = ITEM.ITEM_NO WHERE ITEM.ITEM_STATUS IN ('ACTIVE', 'INACTIVE') AND ITEM.ITEM_NAME LIKE CONCAT('%', #{searchWord}, '%')
AND ITCP.CATEGORY_NO IN #{no}
GROUP BY ITEM.ITEM_NO, ITEM.ITEM_NAME, ITEM.ITEM_STATUS, IMG.IMG_URL
ORDER BY price ASC ORDER BY orderCount DESC ORDER BY ITEM.CREATED_DT DESC
LIMIT #{size} OFFSET ${(page - 1) * size}

